import { useEffect, useState } from 'react';

type Post = { id: string; title: string };

export function PostView({ id }: { id: string }) {
  const [p, setP] = useState<Post | null>(null);
  useEffect(() => {
    const c = new AbortController();
    void fetch(`/api/posts/${id}`, { signal: c.signal })
      .then((r) => r.json() as Promise<Post>)
      .then(setP)
      .catch(() => {}); // only if you handle abort as silent
    return () => c.abort();
  }, [id]);
  return p ? <h1>{p.title}</h1> : <p>Loading…</p>;
}

